#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int Ln[N], Ls[N], Le[N], Lw[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &Ln[i]);
        }
        for (int i = 0; i < N; i++) {
            scanf("%d", &Ls[i]);
        }
        for (int i = 0; i < N; i++) {
            scanf("%d", &Le[i]);
        }
        for (int i = 0; i < N; i++) {
            scanf("%d", &Lw[i]);
        }
        int count = 0;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                if (Ln[i] + Ls[j] > N || Le[i] + Lw[j] > N) {
                    count++;
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

