            }
            for (int i = 0; i < N; i++) {
                Ls[i] = sc.nextInt();
            }
            for (int i = 0; i < N; i++) {
                Le[i] = sc.nextInt();
            }
            for (int i = 0; i < N; i++) {
                Lw[i] = sc.nextInt();
            }
            int count = 0;
